#inbox-panel{width:260px;display:flex;flex-direction:column;background:var(--bg);border-left:1px solid var(--border);overflow:hidden;flex-shrink:0}
#inbox-hdr{background:var(--bg2);border-bottom:1px solid var(--border-gold);padding:7px 10px;display:flex;align-items:center;justify-content:space-between;flex-shrink:0}
.inbox-title{font-size:10px;font-weight:800;color:var(--gold);text-transform:uppercase;letter-spacing:1px}
#inbox-badge{background:var(--red);color:#fff;font-size:9px;font-weight:800;padding:1px 6px;border-radius:10px;display:none}
#inbox-badge.show{display:inline-block}
#inbox-list{flex:1;overflow-y:auto;padding:6px;display:flex;flex-direction:column;gap:4px}
.inbox-item{background:var(--bg2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:7px 9px;cursor:pointer;transition:all var(--t)}
.inbox-item:hover{border-color:var(--gold);background:var(--bg3)}
.inbox-item.unread{border-left:3px solid var(--gold)}
.inbox-item.read{border-left:3px solid transparent;opacity:.65}
.ii-date{font-size:9px;color:var(--muted);font-weight:600;text-transform:uppercase;letter-spacing:.4px}
.ii-subject{font-size:11px;font-weight:700;color:var(--white);margin-top:2px}
.ii-preview{font-size:10px;color:var(--muted);margin-top:2px;line-height:1.3;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.nl-section{margin-bottom:10px}
.nl-stitle{font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px;padding-bottom:3px;border-bottom:1px solid rgba(255,255,255,.07)}
.nl-stitle.pol{color:var(--blue)}.nl-stitle.war{color:var(--red)}.nl-stitle.eco{color:var(--gold)}.nl-stitle.law{color:var(--teal)}.nl-stitle.mkt{color:var(--green)}.nl-stitle.cry{color:var(--purple)}
.nl-body{font-size:11px;color:var(--muted);line-height:1.55}
@media(max-width:960px){#inbox-panel{display:none}}

